-// detectTestFiles identifies files that look like tests based on naming conventions.
-func detectTestFiles(entries []treeEntry) []string {
-	var tests []string
-	for _, e := range entries {
-		if e.IsDir {
-			continue
-		}
-		if isTestFile(e.RelPath) {
-			tests = append(tests, e.RelPath)
-		}
-	}
